SELECT SUM(amount) AS total_transaction_amount
FROM transactions
WHERE customer_id = 2074199;

SELECT SUM(amount) AS total_sales
FROM transactions
WHERE product_id = 123;

SELECT SUM(amount) AS total_revenue
FROM transactions
WHERE product_id = 0;

SELECT AVG(t.amount) AS average_transaction_amount
FROM transactions t
INNER JOIN customer_products cp ON t.customer_id = cp.customer_id;

SELECT SUM(amount) AS total_revenue
FROM transactions
WHERE transaction_channel = 'MAIL';

SELECT DISTINCT customer_id
FROM transactions
WHERE transaction_date > '2023-01-01';

SELECT COUNT(channel_id) AS active_channel_count
FROM sales_channels
WHERE channel_status = 'Active';

SELECT SUM(quantity) AS total_quantity_purchased
FROM customer_products
WHERE customer_id = 2074199;
